features.snippet:
interface a_if ();
    logic req;
    logic ack;
    modport i (
        input req,
        output ack
    );
endinterface

module m1 (
    input wire clk,
    a_if.i foo_if
);
    a_if bar_if();
    always_ff @(posedge clk) bar_if.ack <= ~bar_if.req;
endmodule

module m2 (
    input wire clk,
    a_if.i bar_if
);
    m1 u_m1 ( .clk (clk), .foo_if (bar_if) );
endmodule

module top ();
    a_if dut_if();
    m2 u_dut ( .clk (clk), .bar_if (dut_if) );
endmodule

module m1 (a_if.i foo_if);
    a_if bar_if();
endmodule
